import React, { useState, useEffect } from 'react';
import styled, { keyframes } from 'styled-components';
import { 
  Rocket, 
  Cloud, 
  Server, 
  Globe, 
  CheckCircle, 
  AlertCircle, 
  Clock,
  ExternalLink,
  Play,
  Square,
  Zap,
  Settings,
  RefreshCw,
  Trash2,
  Eye
} from 'lucide-react';

const pulse = keyframes`
  0%, 100% { opacity: 1; transform: scale(1); }
  50% { opacity: 0.7; transform: scale(1.05); }
`;

const slideIn = keyframes`
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
`;

const float = keyframes`
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-10px); }
`;

const Container = styled.div`
  padding: 2rem;
  background: linear-gradient(135deg, #f0f4f8 0%, #e6f7ff 100%);
  min-height: 100vh;
`;

const Header = styled.div`
  margin-bottom: 2rem;
`;

const Title = styled.h1`
  font-size: 2rem;
  font-weight: 700;
  color: #1e293b;
  margin-bottom: 0.5rem;
`;

const Subtitle = styled.p`
  color: #64748b;
  font-size: 1.1rem;
`;

const PlatformGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2rem;
`;

const PlatformCard = styled.div`
  background: white;
  border-radius: 1rem;
  padding: 1.5rem;
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.08);
  border: 2px solid ${props => props.selected ? '#667eea' : '#e2e8f0'};
  cursor: pointer;
  transition: all 0.3s ease;
  position: relative;
  overflow: hidden;
  
  &:hover {
    border-color: #667eea;
    transform: translateY(-5px);
    box-shadow: 0 12px 40px rgba(102, 126, 234, 0.15);
  }
  
  ${props => props.selected && `
    &::before {
      content: '';
      position: absolute;
      top: 0;
      left: 0;
      right: 0;
      height: 4px;
      background: linear-gradient(90deg, #667eea, #764ba2);
    }
  `}
`;

const PlatformHeader = styled.div`
  display: flex;
  align-items: center;
  gap: 1rem;
  margin-bottom: 1rem;
`;

const PlatformIcon = styled.div`
  width: 3.5rem;
  height: 3.5rem;
  border-radius: 1rem;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-size: 1.5rem;
  animation: ${float} 3s ease-in-out infinite;
`;

const PlatformInfo = styled.div`
  flex: 1;
`;

const PlatformName = styled.h3`
  font-size: 1.25rem;
  font-weight: 600;
  color: #1e293b;
  margin: 0;
`;

const PlatformDescription = styled.p`
  color: #64748b;
  font-size: 0.875rem;
  margin: 0;
`;

const FeatureList = styled.ul`
  list-style: none;
  margin: 0;
  padding: 0;
  margin-bottom: 1rem;
`;

const FeatureItem = styled.li`
  display: flex;
  align-items: center;
  gap: 0.5rem;
  color: #64748b;
  font-size: 0.875rem;
  margin-bottom: 0.5rem;
  
  &:last-child {
    margin-bottom: 0;
  }
`;

const DeploymentSection = styled.div`
  background: white;
  border-radius: 1.25rem;
  padding: 2rem;
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.08);
  border: 1px solid #e2e8f0;
  margin-bottom: 2rem;
  animation: ${slideIn} 0.5s ease-out;
`;

const SectionTitle = styled.h2`
  font-size: 1.5rem;
  font-weight: 600;
  color: #1e293b;
  margin-bottom: 1.5rem;
  display: flex;
  align-items: center;
  gap: 0.75rem;
`;

const DeploymentList = styled.div`
  display: flex;
  flex-direction: column;
  gap: 1rem;
`;

const DeploymentItem = styled.div`
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 1.25rem;
  background: #f8fafc;
  border-radius: 0.75rem;
  border: 1px solid #e2e8f0;
  transition: all 0.2s ease;
  
  &:hover {
    background: #f1f5f9;
    border-color: #c7d2fe;
  }
`;

const DeploymentInfo = styled.div`
  display: flex;
  align-items: center;
  gap: 1rem;
`;

const StatusIcon = styled.div`
  width: 2.5rem;
  height: 2.5rem;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  
  &.deployed {
    background: #10b981;
    color: white;
  }
  
  &.deploying {
    background: #f59e0b;
    color: white;
  }
  
  &.failed {
    background: #ef4444;
    color: white;
  }
`;

const DeploymentDetails = styled.div``;

const DeploymentName = styled.h4`
  font-weight: 600;
  color: #1e293b;
  margin: 0;
  margin-bottom: 0.25rem;
`;

const DeploymentMeta = styled.p`
  color: #64748b;
  font-size: 0.875rem;
  margin: 0;
`;

const DeploymentActions = styled.div`
  display: flex;
  align-items: center;
  gap: 0.75rem;
`;

const ActionButton = styled.button`
  background: #f1f5f9;
  border: none;
  width: 2.5rem;
  height: 2.5rem;
  border-radius: 0.5rem;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  color: #64748b;
  transition: all 0.2s ease;
  
  &:hover {
    background: #e2e8f0;
    color: #1e293b;
  }
  
  &.primary {
    background: #667eea;
    color: white;
    
    &:hover {
      background: #5a67d8;
    }
  }
  
  &.secondary {
    background: #dbeafe;
    color: #2563eb;
    
    &:hover {
      background: #bfdbfe;
    }
  }
  
  &.danger {
    background: #fee2e2;
    color: #ef4444;
    
    &:hover {
      background: #fecaca;
    }
  }
`;

const DeployButton = styled.button`
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  border: none;
  padding: 1.25rem 2rem;
  border-radius: 0.75rem;
  font-size: 1.1rem;
  font-weight: 600;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.75rem;
  transition: all 0.3s ease;
  box-shadow: 0 4px 15px rgba(102, 126, 234, 0.3);
  width: 100%;
  margin-bottom: 2rem;
  
  &:hover:not(:disabled) {
    transform: translateY(-3px);
    box-shadow: 0 8px 25px rgba(102, 126, 234, 0.4);
  }
  
  &:disabled {
    opacity: 0.7;
    cursor: not-allowed;
    transform: none;
  }
`;

const LoadingSpinner = styled.div`
  display: inline-flex;
  animation: ${props => props.rotate && rotate} 1s linear infinite;
`;

function Deploy() {
  const [selectedPlatform, setSelectedPlatform] = useState('aws');
  const [loading, setLoading] = useState(false);
  const [deployments, setDeployments] = useState([
    {
      id: 1,
      name: 'E-commerce Platform',
      platform: 'AWS',
      status: 'deployed',
      deployedAt: '2 hours ago',
      url: 'https://ecommerce.example.com'
    },
    {
      id: 2,
      name: 'Analytics Dashboard',
      platform: 'Google Cloud',
      status: 'deploying',
      deployedAt: '15 minutes ago',
      url: null
    },
    {
      id: 3,
      name: 'Blog Platform',
      platform: 'Vercel',
      status: 'failed',
      deployedAt: '1 day ago',
      url: null
    }
  ]);
  
  const supportedPlatforms = [
    {
      id: 'aws',
      name: 'Amazon Web Services',
      description: 'Deploy to AWS with automatic scaling and global CDN',
      icon: <Cloud size={24} />,
      features: ['Auto Scaling', 'Global CDN', '99.99% Uptime', 'Pay-per-use']
    },
    {
      id: 'gcp',
      name: 'Google Cloud Platform',
      description: 'Deploy to Google Cloud with integrated AI services',
      icon: <Globe size={24} />,
      features: ['AI Integration', 'Big Data', 'Global Network', 'Carbon Neutral']
    },
    {
      id: 'azure',
      name: 'Microsoft Azure',
      description: 'Deploy to Azure with enterprise-grade security',
      icon: <Server size={24} />,
      features: ['Enterprise Security', 'Hybrid Cloud', 'DevOps', 'Compliance']
    },
    {
      id: 'docker',
      name: 'Docker',
      description: 'Containerize and deploy with Docker',
      icon: <Server size={24} />,
      features: ['Containerization', 'Portability', 'Microservices', 'DevOps']
    },
    {
      id: 'vercel',
      name: 'Vercel',
      description: 'Deploy frontend applications with zero configuration',
      icon: <Globe size={24} />,
      features: ['Zero Config', 'Global CDN', 'Serverless', 'Git Integration']
    },
    {
      id: 'netlify',
      name: 'Netlify',
      description: 'Deploy static sites with continuous deployment',
      icon: <Cloud size={24} />,
      features: ['Static Sites', 'CD', 'Forms', 'Functions']
    }
  ];
  
  const getStatusIcon = (status) => {
    switch (status) {
      case 'deployed':
        return <CheckCircle size={16} />;
      case 'deploying':
        return <LoadingSpinner rotate><Clock size={16} /></LoadingSpinner>;
      case 'failed':
        return <AlertCircle size={16} />;
      default:
        return <Clock size={16} />;
    }
  };
  
  const handleDeploy = () => {
    setLoading(true);
    // Simulate deployment process
    setTimeout(() => {
      setLoading(false);
      // Add new deployment to the list
      const newDeployment = {
        id: deployments.length + 1,
        name: 'New Application',
        platform: supportedPlatforms.find(p => p.id === selectedPlatform)?.name,
        status: 'deploying',
        deployedAt: 'Just now',
        url: null
      };
      setDeployments([newDeployment, ...deployments]);
    }, 2000);
  };
  
  return (
    <Container>
      <Header>
        <Title>Deploy Applications</Title>
        <Subtitle>Deploy your applications to various cloud platforms with one click</Subtitle>
      </Header>
      
      <PlatformGrid>
        {supportedPlatforms.map((platform) => (
          <PlatformCard
            key={platform.id}
            selected={selectedPlatform === platform.id}
            onClick={() => setSelectedPlatform(platform.id)}
          >
            <PlatformHeader>
              <PlatformIcon>
                {platform.id === 'aws' && <Cloud size={24} />}
                {platform.id === 'gcp' && <Globe size={24} />}
                {platform.id === 'azure' && <Server size={24} />}
                {platform.id === 'docker' && <Server size={24} />}
                {platform.id === 'vercel' && <Globe size={24} />}
                {platform.id === 'netlify' && <Cloud size={24} />}
              </PlatformIcon>
              <PlatformInfo>
                <PlatformName>{platform.name}</PlatformName>
                <PlatformDescription>{platform.description}</PlatformDescription>
              </PlatformInfo>
            </PlatformHeader>
            
            <FeatureList>
              {platform.features.map((feature, index) => (
                <FeatureItem key={index}>
                  <CheckCircle size={16} style={{ color: '#10b981' }} />
                  {feature}
                </FeatureItem>
              ))}
            </FeatureList>
            
            {platform.status && platform.status !== 'Available' && (
              <div style={{ 
                fontSize: '0.75rem', 
                color: platform.status === 'Coming soon' ? '#f59e0b' : '#64748b',
                fontWeight: '500',
                marginTop: '0.5rem'
              }}>
                {platform.status}
              </div>
            )}
          </PlatformCard>
        ))}
      </PlatformGrid>

      <DeployButton onClick={handleDeploy} disabled={loading}>
        {loading ? (
          <>
            <LoadingSpinner><Clock size={20} /></LoadingSpinner>
            Deploying...
          </>
        ) : (
          <>
            <Rocket size={20} />
            Deploy to {supportedPlatforms.find(p => p.id === selectedPlatform)?.name}
          </>
        )}
      </DeployButton>

      <DeploymentSection>
        <SectionTitle>
          <Clock size={20} />
          Recent Deployments
        </SectionTitle>
        <DeploymentList>
          {deployments.map((deployment) => (
            <DeploymentItem key={deployment.id}>
              <DeploymentInfo>
                <StatusIcon className={deployment.status}>
                  {getStatusIcon(deployment.status)}
                </StatusIcon>
                <DeploymentDetails>
                  <DeploymentName>{deployment.name}</DeploymentName>
                  <DeploymentMeta>
                    {deployment.platform} • {deployment.deployedAt}
                  </DeploymentMeta>
                </DeploymentDetails>
              </DeploymentInfo>
              
              <DeploymentActions>
                {deployment.url && (
                  <ActionButton 
                    className="secondary"
                    onClick={() => window.open(deployment.url, '_blank')}
                  >
                    <ExternalLink size={16} />
                  </ActionButton>
                )}
                
                {deployment.status === 'deployed' && (
                  <ActionButton className="danger">
                    <Trash2 size={16} />
                  </ActionButton>
                )}
                
                {deployment.status === 'deploying' && (
                  <ActionButton className="primary">
                    <Play size={16} />
                  </ActionButton>
                )}
                
                {deployment.status === 'failed' && (
                  <ActionButton>
                    <RefreshCw size={16} />
                  </ActionButton>
                )}
                
                <ActionButton>
                  <Eye size={16} />
                </ActionButton>
              </DeploymentActions>
            </DeploymentItem>
          ))}
        </DeploymentList>
      </DeploymentSection>
    </Container>
  );
}

export default Deploy;
